#include <unistd.h>

void bad_privilege_drop() {
    setuid(1000);  // Noncompliant - return value not checked
    setgid(1000);  // Noncompliant - return value not checked
    // Continue execution assuming privilege drop succeeded
}

void another_bad_example() {
    seteuid(getuid()); // Noncompliant - return value ignored
    // Assume we are no longer privileged
}

compliant:
#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>

void good_privilege_drop() {
    if (setuid(1000) != 0) { // Compliant - checking return value
        perror("setuid failed");
        exit(EXIT_FAILURE);
    }
    if (setgid(1000) != 0) { // Compliant - checking return value
        perror("setgid failed");
        exit(EXIT_FAILURE);
    }
}

void another_good_example() {
    if (seteuid(getuid()) != 0) { // Compliant - checking return value
        fprintf(stderr, "Failed to drop privileges\n");
        exit(EXIT_FAILURE);
    }
}
